1	import { uniqueBy } from '@prisma/client-common'
2	import type * as DMMF from '@prisma/dmmf'
3	import * as ts from '@prisma/ts-builders'
4	import indent from 'indent-string'
5	
6	import { GenericArgsInfo } from '../GenericsArgsInfo'
7	import { appendSkipType } from '../utils'
8	import { GraphQLScalarToJSTypeTable, JSOutputTypeToInputType } from '../utils/common'
9	import { TAB_SIZE } from './constants'
10	import { GenerateContext } from './GenerateContext'
11	
12	export class InputField {
13	  constructor(
14	    protected readonly field: DMMF.SchemaArg,
15	    protected readonly context: GenerateContext,
16	    protected readonly source?: string,
17	  ) {}
18	  public toTS(): string {
19	    const property = buildInputField(this.field, this.context, this.source)
20	    return ts.stringify(property)
21	  }
22	}
23	
24	export function buildInputField(field: DMMF.SchemaArg, context: GenerateContext, source?: string): ts.Property {
25	  const tsType = buildAllFieldTypes(field.inputTypes, context, source)
26	
27	  const tsProperty = ts.property(field.name, field.isRequired ? tsType : appendSkipType(context, tsType))
28	  if (!field.isRequired) {
29	    tsProperty.optional()
30	  }
31	  const docComment = ts.docComment()
32	  if (field.comment) {
33	    docComment.addText(field.comment)
34	  }
35	  if (field.deprecation) {
36	    docComment.addText(`@deprecated since ${field.deprecation.sinceVersion}: ${field.deprecation.reason}`)
37	  }
38	
39	  if (docComment.lines.length > 0) {
40	    tsProperty.setDocComment(docComment)
41	  }
42	
43	  return tsProperty
44	}
45	
46	function buildSingleFieldType(t: DMMF.InputTypeRef, genericsInfo: GenericArgsInfo, source?: string): ts.TypeBuilder {
47	  let type: ts.NamedType
48	
49	  const scalarType = GraphQLScalarToJSTypeTable[t.type]
50	  if (t.location === 'enumTypes' && t.namespace === 'model') {
51	    type = ts.namedType(`$Enums.${t.type}`)
52	  } else if (t.type === 'Null') {
53	    return ts.nullType
54	  } else if (Array.isArray(scalarType)) {
55	    const union = ts.unionType(scalarType.map(namedInputType))
56	    if (t.isList) {
57	      return union.mapVariants((variant) => ts.array(variant))
58	    }
59	    return union
60	  } else if (t.namespace === 'prisma') {
61	    type = namedInputType(`Prisma.${t.type}`)
62	  } else {
63	    type = namedInputType(scalarType ?? t.type)
64	  }
65	
66	  if (genericsInfo.typeRefNeedsGenericModelArg(t)) {
67	    if (source) {
68	      type.addGenericArgument(ts.stringLiteral(source))
69	    } else {
70	      type.addGenericArgument(ts.namedType('$PrismaModel'))
71	    }
72	  }
73	
74	  if (t.isList) {
75	    return ts.array(type)
76	  }
77	
78	  return type
79	}
80	
81	function namedInputType(typeName: string) {
82	  const typeNameParts = typeName.split('.')
83	  const typeNameWithoutNamespace = typeNameParts[typeNameParts.length - 1]
84	  const mappedInputTypeName = JSOutputTypeToInputType[typeNameWithoutNamespace] ?? typeNameWithoutNamespace
85	  return ts.namedType(typeNameParts.slice(0, -1).concat(mappedInputTypeName).join('.'))
86	}
87	
88	/**
89	 * Examples:
90	 * T[], T => T | T[]
91	 * T, U => XOR<T,U>
92	 * T[], T, U => XOR<T, U> | T[]
93	 * T[], U => T[] | U
94	 * T, U, null => XOR<T,U> | null
95	 * T, U, V, W, null => XOR<T, XOR<U, XOR<V, W>>> | null
96	 *
97	 * 1. Separate XOR and non XOR items (objects and non-objects)
98	 * 2. Generate them out and `|` them
99	 */
100	function buildAllFieldTypes(
101	  inputTypes: readonly DMMF.InputTypeRef[],
102	  context: GenerateContext,
103	  source?: string,
104	): ts.TypeBuilder {
105	  const inputObjectTypes = inputTypes.filter((t) => t.location === 'inputObjectTypes' && !t.isList)
106	
107	  const otherTypes = inputTypes.filter((t) => t.location !== 'inputObjectTypes' || t.isList)
108	
109	  const tsInputObjectTypes = inputObjectTypes.map((type) => buildSingleFieldType(type, context.genericArgsInfo, source))
110	
111	  const tsOtherTypes = otherTypes.map((type) => buildSingleFieldType(type, context.genericArgsInfo, source))
112	
113	  if (tsOtherTypes.length === 0) {
114	    return xorTypes(tsInputObjectTypes)
115	  }
116	
117	  if (tsInputObjectTypes.length === 0) {
118	    return ts.unionType(tsOtherTypes)
119	  }
