19	  }
20	  let fieldType: ts.TypeBuilder
21	  if (field.kind === 'object') {
22	    const payloadType = ts.namedType(getPayloadName(field.type))
23	    if (!dmmf.isComposite(field.type)) {
24	      payloadType.addGenericArgument(ts.namedType('ExtArgs'))
