3	
4	export class UnionType<VariantType extends TypeBuilder = TypeBuilder> extends TypeBuilder {
5	  needsParenthesisWhenIndexed = true
6	  needsParenthesisInKeyof = true
7	  needsParenthesisInIntersection = true
8	  readonly variants: VariantType[]
9	
10	  constructor(firstType: VariantType) {
11	    super()
12	    this.variants = [firstType]
13	  }
14	
15	  addVariant(variant: VariantType) {
16	    this.variants.push(variant)
17	    return this
18	  }
19	
20	  addVariants(variants: VariantType[]) {
21	    for (const variant of variants) {
22	      this.addVariant(variant)
23	    }
24	    return this
25	  }
26	
27	  write(writer: Writer): void {
28	    writer.writeJoined(' | ', this.variants, (variant, writer) => {
29	      if (variant.needsParenthesisInUnion) {
30	        writer.write('(').write(variant).write(')')
31	      } else {
32	        writer.write(variant)
33	      }
34	    })
35	  }
36	
37	  mapVariants<NewVariantType extends TypeBuilder>(
38	    callback: (type: VariantType) => NewVariantType,
39	  ): UnionType<NewVariantType> {
40	    return unionType(this.variants.map((v) => callback(v)))
41	  }
42	}
43	
44	export function unionType<VariantType extends TypeBuilder = TypeBuilder>(types: VariantType[] | VariantType) {
45	  if (Array.isArray(types)) {
46	    if (types.length === 0) {
47	      throw new TypeError('Union types array can not be empty')
48	    }
49	    const union = new UnionType(types[0])
50	    for (let i = 1; i < types.length; i++) {
51	      union.addVariant(types[i])
52	    }
53	    return union
54	  }
55	  return new UnionType(types)
56	}
