3	import indent from 'indent-string'
4	
5	import { TAB_SIZE } from './constants'
6	
7	export class Enum {
8	  constructor(
9	    protected readonly type: DMMF.SchemaEnum,
10	    protected readonly useNamespace: boolean,
11	  ) {}
12	
13	  private isObjectEnum(): boolean {
14	    return this.useNamespace && objectEnumNames.includes(this.type.name)
15	  }
16	
17	  private isStrictEnum(): boolean {
18	    return this.useNamespace && strictEnumNames.includes(this.type.name)
19	  }
20	
21	  public toTS(): string {
22	    const { type } = this
23	
24	    const enumVariants = `{
25	${indent(type.values.map((v) => `${v}: ${this.getValue(v)}`).join(',\n'), TAB_SIZE)}
26	} as const`
27	    const enumBody = this.isStrictEnum() ? `runtime.makeStrictEnum(${enumVariants})` : enumVariants
28	
29	    return `export const ${type.name} = ${enumBody}
30	
31	export type ${type.name} = (typeof ${type.name})[keyof typeof ${type.name}]\n`
32	  }
33	
34	  private getValue(value: string): string {
35	    return this.isObjectEnum() ? value : `'${value}'`
36	  }
