2	
3	import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
4	
5	import * as JsonRpc from './json-rpc'
6	
7	export interface Handler {
8	  onGenerate(options: GeneratorOptions): Promise<any>
9	  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
10	}
11	
12	export function generatorHandler(handler: Handler): void {
13	  const stdinInterface = readline.createInterface({
14	    input: process.stdin,
15	    crlfDelay: Infinity,
16	  })
17	
18	  stdinInterface.on('line', async (line: string) => {
19	    const json = JSON.parse(line)
20	
21	    if (json.method === 'generate' && json.params) {
22	      try {
23	        const result = await handler.onGenerate(json.params)
24	        respond({
25	          jsonrpc: '2.0',
26	          result: result,
27	          id: json.id,
28	        })
