  models: Model[]           // Your models (User, Post, etc.)
  enums: DatamodelEnum[]    // Your enums
  types: Model[]            // Composite types
  indexes: Index[]          // Database indexes
}>

export type Model = ReadonlyDeep<{
  name: string              // "User", "Post", etc.
  dbName: string | null     // Actual DB table name
  schema: string | null     // Database schema
  fields: Field[]           // Model fields
  uniqueFields: string[][]  // Unique field combinations
  uniqueIndexes: uniqueIndex[]
  documentation?: string    // From /// comments
  primaryKey: PrimaryKey | null
  isGenerated?: boolean     // Generated (e.g., view)
}>

export type Field = ReadonlyDeep<{
  kind: FieldKind           // 'scalar' | 'object' | 'enum' | 'unsupported'
  name: string              // Field name
  isRequired: boolean       // Required (not optional)
  isList: boolean           // Array field
  isUnique: boolean         // Unique constraint
  isId: boolean             // Primary key
  isReadOnly: boolean       // @updatedAt etc.
  isGenerated?: boolean     // Auto-generated
  isUpdatedAt?: boolean     // @updatedAt field
  type: string              // "String", "Int", "DateTime", "$User" (relations), etc.
  nativeType?: [string, string[]] | null  // DB type like ["VarChar", ["191"]]
  dbName?: string | null    // @map("db_field_name")
  hasDefaultValue: boolean
  default?: FieldDefault | FieldDefaultScalar | FieldDefaultScalar[]
  relationFromFields?: string[]  // FK field names
  relationToFields?: string[]    // Referenced field names
  relationOnDelete?: string      // CASCADE, SET NULL, etc.
  relationOnUpdate?: string
  relationName?: string      // Name of relation
  documentation?: string
}>

export type FieldKind = 'scalar' | 'object' | 'enum' | 'unsupported'
```

### SCHEMA Section (GraphQL schema):

```typescript
export type Schema = ReadonlyDeep<{
  rootQueryType?: string
  rootMutationType?: string
  inputObjectTypes: {
    model?: InputType[]      // Input types for model operations
    prisma?: InputType[]     // Prisma input types
  }
  outputObjectTypes: {
    model: OutputType[]
    prisma: OutputType[]
  }
  enumTypes: {
    model?: SchemaEnum[]
    prisma: SchemaEnum[]
  }
  fieldRefTypes: {
    prisma?: FieldRefType[]
  }
}>

export type OutputType = ReadonlyDeep<{
  name: string              // "User", "UserCreateInput", etc.
  fields: SchemaField[]
}>

export type SchemaField = ReadonlyDeep<{
  name: string
  isNullable?: boolean
  outputType: OutputTypeRef
  args: SchemaArg[]
  documentation?: string
}>

export type InputType = ReadonlyDeep<{
  name: string
  constraints: {
    maxNumFields: number | null
    minNumFields: number | null
    fields?: string[]
  }
  meta?: {
    source?: string
    grouping?: string
  }
