import type * as DMMF from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Maps a Prisma DMMF field type to a TypeScript type string.
 * Scalar types are mapped to their TS equivalents, enums to their names,
 * and relation fields to their model interface names.
 */
export function mapFieldToTsType(field: DMMF.Field, enumNames: Set<string>): string {
  const baseType = resolveBaseType(field, enumNames)

  if (field.isList) {
    return `${baseType}[]`
  }

  if (!field.isRequired) {
    return `${baseType} | null`
  }

  return baseType
}

function resolveBaseType(field: DMMF.Field, enumNames: Set<string>): string {
  if (field.kind === 'scalar') {
    return SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }

  if (field.kind === 'enum' || enumNames.has(field.type)) {
    return field.type
  }

  if (field.kind === 'object') {
    return field.type
  }

  return 'unknown'
}

/** Returns true if the field is a relation (object) field rather than a scalar/enum. */
export function isRelationField(field: DMMF.Field): boolean {
  return field.kind === 'object'
}

