import type * as DMMF from '@prisma/dmmf'

import { isRelationField, mapFieldToTsType } from './type-mapper'

/**
 * Generates a complete typed REST API client module from a DMMF document.
 * Produces TypeScript interfaces for each model and enum, plus a client class
 * with CRUD methods per model.
 */
export function generateRestApiClient(dmmf: DMMF.Document, baseUrl: string): string {
  const { models, enums } = dmmf.datamodel
  const enumNames = new Set(enums.map((e) => e.name))

  const parts: string[] = [generateHeader(baseUrl), generateEnums(enums), generateModelInterfaces(models, enumNames)]

  for (const model of models) {
    parts.push(generateCreateInput(model, enumNames))
    parts.push(generateUpdateInput(model, enumNames))
  }

  parts.push(generateClientClass(models))

  return parts.filter(Boolean).join('\n\n') + '\n'
}

function generateHeader(baseUrl: string): string {
  const lines = [
    '// Generated by @prisma/rest-api-generator — do not edit manually',
    '',
    `const BASE_URL = '${baseUrl}'`,
    '',
    'type RequestOptions = {',
    '  headers?: Record<string, string>',
    '}',
    '',
    'async function request<T>(path: string, options: RequestInit & RequestOptions = {}): Promise<T> {',
    '  const { headers: extraHeaders, ...init } = options',
    '  const res = await fetch(`${BASE_URL}${path}`, {',
    "    ...init,",
    '    headers: {',
    "      'Content-Type': 'application/json',",
    '      ...extraHeaders,',
    '    },',
    '  })',
    '  if (!res.ok) {',
    '    throw new Error(`REST API error: ${res.status} ${res.statusText}`)',
    '  }',
    '  return res.json() as Promise<T>',
    '}',
  ]
  return lines.join('\n')
}

function generateEnums(enums: readonly DMMF.DatamodelEnum[]): string {
  return enums.map((e) => generateEnum(e)).join('\n\n')
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${values}\n}`
}

function generateModelInterfaces(models: readonly DMMF.Model[], enumNames: Set<string>): string {
  return models.map((model) => generateModelInterface(model, enumNames)).join('\n\n')
}

function generateModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.map((field) => {
    const tsType = mapFieldToTsType(field, enumNames)
    const optional = !field.isRequired && !field.isList ? '?' : ''
    return `  ${field.name}${optional}: ${tsType}`
  })

  const docComment = model.documentation ? `/** ${model.documentation} */\n` : ''
  return `${docComment}export interface ${model.name} {\n${fields.join('\n')}\n}`
}

/**
 * Generates a CreateInput type that omits auto-generated fields (id with default,
 * createdAt/updatedAt, relation fields).
 */
function generateCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter((f) => {
    if (isRelationField(f)) return false
    if (f.isGenerated) return false
    if (f.isUpdatedAt) return false
    if (f.isReadOnly) return false
    return true
  })

  const fieldLines = fields.map((field) => {
    const tsType = mapFieldToTsType(field, enumNames)
    const optional = !field.isRequired || field.hasDefaultValue || field.isList ? '?' : ''
    return `  ${field.name}${optional}: ${tsType}`
  })

  return `export interface ${model.name}CreateInput {\n${fieldLines.join('\n')}\n}`
}

/** Generates an UpdateInput type where all scalar/enum fields are optional. */
function generateUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields.filter((f) => {
    if (isRelationField(f)) return false
    if (f.isGenerated) return false
    if (f.isReadOnly) return false
    return true
  })

  const fieldLines = fields.map((field) => {
    const baseType = mapFieldToTsType(field, enumNames)
    return `  ${field.name}?: ${baseType}`
  })

  return `export interface ${model.name}UpdateInput {\n${fieldLines.join('\n')}\n}`
}

function generateClientClass(models: readonly DMMF.Model[]): string {
  const modelMethods = models.map((model) => generateModelMethods(model)).join('\n\n')

  return [
    'export class RestApiClient {',
    '  #options: RequestOptions',
    '',
    '  constructor(options: RequestOptions = {}) {',
    '    this.#options = options',
    '  }',
    '',
    modelMethods,
    '}',
  ].join('\n')
}

function generateModelMethods(model: DMMF.Model): string {
  const name = model.name
  const resource = toResourcePath(name)

  const idField = model.fields.find((f) => f.isId)
  const idType = idField ? (idField.type === 'Int' ? 'number' : 'string') : 'string'

  return [
    `  /** Retrieve all ${name} records. */`,
    `  async ${lowerFirst(name)}FindMany(): Promise<${name}[]> {`,
    `    return request<${name}[]>('/${resource}', this.#options)`,
    '  }',
    '',
    `  /** Retrieve a single ${name} by its unique identifier. */`,
    `  async ${lowerFirst(name)}FindUnique(id: ${idType}): Promise<${name}> {`,
    `    return request<${name}>(\`/${resource}/\${id}\`, this.#options)`,
    '  }',
    '',
    `  /** Create a new ${name} record. */`,
    `  async ${lowerFirst(name)}Create(data: ${name}CreateInput): Promise<${name}> {`,
    `    return request<${name}>('/${resource}', {`,
    `      ...this.#options,`,
    `      method: 'POST',`,
    `      body: JSON.stringify(data),`,
    `    })`,
    '  }',
    '',
