    `  async ${lowerFirst(name)}Delete(id: ${idType}): Promise<${name}> {`,
    `    return request<${name}>(\`/${resource}/\${id}\`, {`,
    `      ...this.#options,`,
    `      method: 'DELETE',`,
    `    })`,
    '  }',
  ].join('\n')
}

function toResourcePath(modelName: string): string {
  return modelName
    .replace(/([a-z])([A-Z])/g, '$1-$2')
    .toLowerCase()
