import fs from 'node:fs'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import type { Generator } from '@prisma/generator'

import { generateRestApiClient } from './code-generator'

const VERSION = '0.0.0'
const DEFAULT_BASE_URL = '/api'

/**
 * Prisma generator that produces a typed REST API client.
 *
 * For each model in the schema it generates TypeScript interfaces and
 * CRUD methods (findMany, findUnique, create, update, delete) with
 * proper types.
 */
export class RestApiGenerator implements Generator {
  readonly name = 'prisma-rest-api'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      defaultOutput: './generated/rest-api-client',
      prettyName: 'Prisma REST API Client',
      version: VERSION,
      requiresEngines: [],
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const output = options.generator.output
    if (!output?.value) {
      throw new Error('No output directory specified for rest-api-generator')
    }

    const outputDir = output.value
    const baseUrl = options.generator.config.baseUrl ?? DEFAULT_BASE_URL

    if (typeof baseUrl !== 'string') {
      throw new Error('baseUrl config option must be a string')
    }

    const code = generateRestApiClient(options.dmmf, baseUrl)

    await fs.promises.mkdir(outputDir, { recursive: true })
    await fs.promises.writeFile(path.join(outputDir, 'index.ts'), code, 'utf-8')
  }
}

