import { generateRestApiClient } from '../code-generator'

function createMinimalDmmf(overrides: {
  models?: DMMF.Model[]
  enums?: DMMF.DatamodelEnum[]
}): DMMF.Document {
  return {
    datamodel: {
      models: overrides.models ?? [],
      enums: overrides.enums ?? [],
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function createModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    isGenerated: false,
  } as DMMF.Model
}

function createField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

