import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorConfig, GeneratorOptions } from '@prisma/generator'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { RestApiGenerator } from '../generator'

function createGeneratorOptions(overrides: {
  outputDir: string
  baseUrl?: string
  models?: DMMF.Model[]
  enums?: DMMF.DatamodelEnum[]
}): GeneratorOptions {
  const config: Record<string, string | undefined> = {}
  if (overrides.baseUrl) {
    config.baseUrl = overrides.baseUrl
  }

  return {
    generator: {
      name: 'rest-api',
      output: { fromEnvVar: null, value: overrides.outputDir },
      provider: { fromEnvVar: null, value: 'prisma-rest-api' },
      config,
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    } as GeneratorConfig,
    otherGenerators: [],
    schemaPath: '/tmp/schema.prisma',
    dmmf: {
      datamodel: {
        models: overrides.models ?? [
          {
            name: 'User',
            dbName: null,
            schema: null,
            fields: [
              {
                kind: 'scalar',
                name: 'id',
                isRequired: true,
                isList: false,
                isUnique: false,
                isId: true,
                isReadOnly: false,
                type: 'Int',
                hasDefaultValue: true,
                default: { name: 'autoincrement', args: [] },
              },
              {
                kind: 'scalar',
                name: 'email',
                isRequired: true,
                isList: false,
                isUnique: true,
                isId: false,
                isReadOnly: false,
                type: 'String',
                hasDefaultValue: false,
              },
            ],
            uniqueFields: [],
            uniqueIndexes: [],
            primaryKey: null,
          },
        ],
        enums: overrides.enums ?? [],
        types: [],
        indexes: [],
      },
      schema: {
        inputObjectTypes: {},
        outputObjectTypes: { model: [], prisma: [] },
        enumTypes: { prisma: [] },
        fieldRefTypes: {},
      },
      mappings: {
        modelOperations: [],
        otherOperations: { read: [], write: [] },
      },
    } as unknown as DMMF.Document,
    datasources: [],
    datamodel: '',
    version: 'test-version',
  }
}

describe('RestApiGenerator', () => {
  const generator = new RestApiGenerator()
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.promises.mkdtemp(path.join(os.tmpdir(), 'rest-api-gen-'))
  })

  afterEach(async () => {
    await fs.promises.rm(tmpDir, { recursive: true, force: true })
  })

  describe('getManifest', () => {
    test('returns the expected manifest', async () => {
      const manifest = await generator.getManifest({
        name: 'rest-api',
        output: null,
        provider: { fromEnvVar: null, value: 'prisma-rest-api' },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '',
      } as GeneratorConfig)

      expect(manifest.prettyName).toBe('Prisma REST API Client')
      expect(manifest.defaultOutput).toBe('./generated/rest-api-client')
      expect(manifest.requiresEngines).toEqual([])
    })
  })

  describe('generate', () => {
    test('creates the output directory and writes index.ts', async () => {
      const outputDir = path.join(tmpDir, 'output')
      const options = createGeneratorOptions({ outputDir })

      await generator.generate(options)

      const outputFile = path.join(outputDir, 'index.ts')
      const content = await fs.promises.readFile(outputFile, 'utf-8')

      expect(content).toContain('export interface User {')
      expect(content).toContain('export class RestApiClient {')
      expect(content).toContain("const BASE_URL = '/api'")
    })

    test('uses custom baseUrl from config', async () => {
      const outputDir = path.join(tmpDir, 'output-custom')
      const options = createGeneratorOptions({
        outputDir,
        baseUrl: 'https://api.example.com',
      })

      await generator.generate(options)

      const outputFile = path.join(outputDir, 'index.ts')
      const content = await fs.promises.readFile(outputFile, 'utf-8')

      expect(content).toContain("const BASE_URL = 'https://api.example.com'")
    })

    test('throws when output is not specified', async () => {
      const options = createGeneratorOptions({ outputDir: tmpDir })
      options.generator.output = null

      await expect(generator.generate(options)).rejects.toThrow('No output directory specified')
    })

    test('generates CRUD methods for the model', async () => {
      const outputDir = path.join(tmpDir, 'output-crud')
      const options = createGeneratorOptions({ outputDir })

      await generator.generate(options)

      const content = await fs.promises.readFile(path.join(outputDir, 'index.ts'), 'utf-8')

      expect(content).toContain('async userFindMany(): Promise<User[]>')
      expect(content).toContain('async userFindUnique(id: number): Promise<User>')
      expect(content).toContain('async userCreate(data: UserCreateInput): Promise<User>')
      expect(content).toContain('async userUpdate(id: number, data: UserUpdateInput): Promise<User>')
      expect(content).toContain('async userDelete(id: number): Promise<User>')
    })

    test('creates nested output directories', async () => {
      const outputDir = path.join(tmpDir, 'a', 'b', 'c')
      const options = createGeneratorOptions({ outputDir })

      await generator.generate(options)

      const exists = fs.existsSync(path.join(outputDir, 'index.ts'))
      expect(exists).toBe(true)
    })
  })
})

