import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestApiClient } from '../code-generator'

function createMinimalDmmf(overrides: {
  models?: DMMF.Model[]
  enums?: DMMF.DatamodelEnum[]
}): DMMF.Document {
  return {
    datamodel: {
      models: overrides.models ?? [],
      enums: overrides.enums ?? [],
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function createModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    isGenerated: false,
  } as DMMF.Model
}

function createField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

describe('generateRestApiClient', () => {
  test('generates a header with the configured base URL', () => {
    const dmmf = createMinimalDmmf({})
    const output = generateRestApiClient(dmmf, '/api/v1')

    expect(output).toContain("const BASE_URL = '/api/v1'")
    expect(output).toContain('async function request<T>')
  })

  test('generates interfaces for models', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('User', [
          createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          createField({ name: 'email', type: 'String', isUnique: true }),
          createField({ name: 'name', type: 'String', isRequired: false }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name?: string | null')
  })

  test('generates CreateInput types omitting auto-generated fields', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('User', [
          createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          createField({ name: 'email', type: 'String' }),
          createField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
          createField({ name: 'posts', type: 'Post', kind: 'object', isList: true }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('export interface UserCreateInput {')
    expect(output).toContain('  email: string')
    // id has default value, so it should be optional in create input
    expect(output).toMatch(/id\?: number/)
    // updatedAt and relation should be excluded
    expect(output).not.toMatch(/UserCreateInput[\s\S]*?updatedAt/)
    expect(output).not.toMatch(/UserCreateInput[\s\S]*?posts.*Post/)
  })

  test('generates UpdateInput types with all fields optional', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('User', [
          createField({ name: 'id', type: 'Int', isId: true }),
          createField({ name: 'email', type: 'String' }),
          createField({ name: 'name', type: 'String', isRequired: false }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toContain('  id?: number')
    expect(output).toContain('  email?: string')
    expect(output).toContain('  name?: string | null')
  })

  test('generates enums', () => {
    const dmmf = createMinimalDmmf({
      enums: [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('export enum Role {')
    expect(output).toContain("  ADMIN = 'ADMIN',")
    expect(output).toContain("  USER = 'USER',")
  })

  test('generates CRUD methods for models in the client class', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('Post', [
          createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          createField({ name: 'title', type: 'String' }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('export class RestApiClient {')
    expect(output).toContain('async postFindMany(): Promise<Post[]>')
    expect(output).toContain('async postFindUnique(id: number): Promise<Post>')
    expect(output).toContain('async postCreate(data: PostCreateInput): Promise<Post>')
    expect(output).toContain('async postUpdate(id: number, data: PostUpdateInput): Promise<Post>')
    expect(output).toContain('async postDelete(id: number): Promise<Post>')
  })

  test('uses string id type for non-Int id fields', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('Account', [
          createField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
          createField({ name: 'name', type: 'String' }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('async accountFindUnique(id: string): Promise<Account>')
  })

  test('generates correct REST resource paths', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('BlogPost', [
          createField({ name: 'id', type: 'Int', isId: true }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    // BlogPost -> blog-posts
    expect(output).toContain("'/blog-posts'")
  })

  test('handles multiple models', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('User', [
          createField({ name: 'id', type: 'Int', isId: true }),
          createField({ name: 'email', type: 'String' }),
        ]),
        createModel('Post', [
          createField({ name: 'id', type: 'Int', isId: true }),
          createField({ name: 'title', type: 'String' }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('export interface User {')
    expect(output).toContain('export interface Post {')
    expect(output).toContain('async userFindMany(): Promise<User[]>')
    expect(output).toContain('async postFindMany(): Promise<Post[]>')
  })

  test('generates valid HTTP methods for CRUD operations', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('Item', [
          createField({ name: 'id', type: 'Int', isId: true }),
        ]),
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain("method: 'POST'")
    expect(output).toContain("method: 'PATCH'")
    expect(output).toContain("method: 'DELETE'")
  })

  test('uses enum types in model interfaces', () => {
    const dmmf = createMinimalDmmf({
      models: [
        createModel('User', [
          createField({ name: 'id', type: 'Int', isId: true }),
          createField({ name: 'role', type: 'Role', kind: 'enum' }),
        ]),
      ],
      enums: [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
    })

    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('  role: Role')
  })

  test('handles empty schema with no models', () => {
    const dmmf = createMinimalDmmf({})
    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain("const BASE_URL = '/api'")
    expect(output).toContain('export class RestApiClient {')
  })

  test('model documentation is included in the interface', () => {
    const model = createModel('User', [
      createField({ name: 'id', type: 'Int', isId: true }),
    ])
    ;(model as any).documentation = 'Represents a user account'

    const dmmf = createMinimalDmmf({ models: [model] })
    const output = generateRestApiClient(dmmf, '/api')

    expect(output).toContain('/** Represents a user account */')
    expect(output).toContain('export interface User {')
  })
})

